<template><div class="space-y-4"><div class="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3"><h2 class="text-xl font-bold" style="color:#00f0ff">🪙 Token用量</h2><div class="flex gap-2 flex-wrap"><input v-model="search" placeholder="搜索..." class="px-3 py-1.5 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/><button @click="refresh" class="px-3 py-1.5 rounded-lg text-sm" style="background:#00f0ff20;color:#00f0ff;border:1px solid #00f0ff40">刷新</button><button @click="showAdd=!showAdd" class="px-3 py-1.5 rounded-lg text-sm" style="background:#ff2d9520;color:#ff2d95;border:1px solid #ff2d9540">+新增</button></div></div><div v-if="showAdd" class="cyber-card rounded-xl p-4"><h3 class="text-sm font-bold mb-3" style="color:#ff2d95">新增记录</h3><div class="grid grid-cols-2 md:grid-cols-5 gap-3"><input v-model="newRow['model']" placeholder="模型" class="px-3 py-2 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/><input v-model="newRow['today']" placeholder="今日Token" class="px-3 py-2 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/><input v-model="newRow['month']" placeholder="本月Token" class="px-3 py-2 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/><input v-model="newRow['cost']" placeholder="费用" class="px-3 py-2 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/><input v-model="newRow['quota']" placeholder="配额" class="px-3 py-2 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/></div><button @click="addRow" class="mt-3 px-4 py-2 rounded-lg text-sm" style="background:linear-gradient(135deg,#00f0ff,#b700ff);color:#fff">确认添加</button></div><div class="cyber-card rounded-xl overflow-hidden"><div class="overflow-x-auto"><table class="w-full"><thead><tr style="background:#0d0d1a"><th class="px-3 py-3 text-left text-xs font-medium" style="color:#ff2d95">模型</th><th class="px-3 py-3 text-left text-xs font-medium" style="color:#ff2d95">今日Token</th><th class="px-3 py-3 text-left text-xs font-medium" style="color:#ff2d95">本月Token</th><th class="px-3 py-3 text-left text-xs font-medium" style="color:#ff2d95">费用</th><th class="px-3 py-3 text-left text-xs font-medium" style="color:#ff2d95">配额</th><th class="px-3 py-3 text-left text-xs" style="color:#ff2d95">操作</th></tr></thead><tbody><tr v-for="row in paged" :key="row._id" class="border-t hover:bg-white/5" style="border-color:#00f0ff10"><td class="px-3 py-3 text-sm whitespace-nowrap" style="color:#e0e0ff">{{ row["model"] }}</td><td class="px-3 py-3 text-sm whitespace-nowrap" style="color:#e0e0ff">{{ row["today"] }}</td><td class="px-3 py-3 text-sm whitespace-nowrap" style="color:#e0e0ff">{{ row["month"] }}</td><td class="px-3 py-3 text-sm whitespace-nowrap" style="color:#e0e0ff">{{ row["cost"] }}</td><td class="px-3 py-3 text-sm whitespace-nowrap" style="color:#e0e0ff">{{ row["quota"] }}</td><td class="px-3 py-3 text-sm whitespace-nowrap"><button @click="editRow(row)" class="mr-2 text-xs px-2 py-1 rounded" style="color:#00f0ff;background:#00f0ff15">编辑</button><button @click="delRow(row._id)" class="text-xs px-2 py-1 rounded" style="color:#ff2d95;background:#ff2d9515">删除</button></td></tr></tbody></table></div><div class="flex items-center justify-between px-4 py-3 border-t" style="border-color:#00f0ff10"><span class="text-xs" style="color:#a0a0cc">共 {{ filtered.length }} 条</span><div class="flex gap-1"><button v-for="p in totalPages" :key="p" @click="page=p" class="px-2 py-1 rounded text-xs" :style="page===p?'background:#00f0ff;color:#0d0d1a':'color:#a0a0cc;background:#00f0ff10'">{{ p }}</button></div></div></div></div></template>
<script setup lang="ts">
import {ref,computed} from 'vue'
const search=ref(''),showAdd=ref(false),page=ref(1),perPage=10
const newRow=ref<Record<string,string>>({ 'model':'', 'today':'', 'month':'', 'cost':'', 'quota':'' })
const names=["张三","李四","王五","赵六","钱七","孙八","周九","吴十","郑一","冯二","陈明","林华","黄磊","杨洋","刘洋","马超","许嵩","韩雪","曹操","魏征"]
function rid(){return Math.random().toString(36).slice(2,10)}
function rd(){const d=new Date(Date.now()-Math.random()*2592e6);return d.toLocaleDateString('zh-CN')+' '+d.toTimeString().slice(0,5)}
function rip(){return [1,2,3,4].map(()=>Math.floor(Math.random()*223+1)).join('.')}
function gen(){return Array.from({length:35},(_,i)=>({_id:rid(),'model':'示例'+(i+1), 'today':String(Math.floor(Math.random()*10000)), 'month':String(Math.floor(Math.random()*10000)), 'cost':'¥'+(Math.random()*1000).toFixed(2), 'quota':'示例'+(i+1)}))}
const rows=ref<any[]>(gen())
const filtered=computed(()=>{const s=search.value.toLowerCase();return s?rows.value.filter(r=>Object.values(r).some(v=>String(v).toLowerCase().includes(s))):rows.value})
const totalPages=computed(()=>Math.max(1,Math.ceil(filtered.value.length/perPage)))
const paged=computed(()=>filtered.value.slice((page.value-1)*perPage,page.value*perPage))
function refresh(){rows.value=gen()}
function addRow(){const v=newRow.value;if(Object.values(v).some(x=>x)){rows.value.unshift({_id:rid(),...v});Object.keys(v).forEach(k=>v[k]='');showAdd.value=false}}
function editRow(r:any){alert('编辑: '+JSON.stringify(r))}
function delRow(id:string){rows.value=rows.value.filter(r=>r._id!==id)}
</script>